var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"성찬을 준비하라. 새로운 날이 당도하리니.","JPN":"聖餐を準備しろ。新しい日が到来する。","ENG":"Prepare the feast. A new dawn is coming.","TWN":"預備盛宴吧。新天已來到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"불완전한 지식, 불완전한 존재들이 성찬을 통해 하나가 되어, 완전해질 것이다.","JPN":"不完全な知識、不完全な存在たちが聖餐により一つになり、完全体となる。","ENG":"The feast will complete the imperfect knowledge and perfect the imperfect beings.","TWN":"不完整的知識，不完整的存在將透過盛宴合而為一，變得完整。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"모두 지식의 성찬을 준비하라.\\n모두 연회를 시작하라.","JPN":"みんな、知識の聖餐を準備しろ。\\nみんな、宴会を始めろ。","ENG":"Prepare the feast of knowledge.\\nStart the banquet.","TWN":"大家準備知識的盛宴吧，\\n大家開始宴會吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"오랜 갈구와 허기의 끝이 마침내 도래했다.","JPN":"長い渇きと飢えの果てが、ついに訪れたのだ。","ENG":"Today, the blood and flesh of the young lamb will be on the table,\\nand the swallower shall become the swallowed.","TWN":"長久的渴望與饑餓終於到達了盡頭。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"오늘의 성찬은 어린 양의 피와 살일지니.\\n삼키는 자가 삼켜지고, 삼켜지는 자가 삼키리라.","JPN":"今日は子羊の血と肉が聖餐となり、\\n飲み込む者が飲み込まれ、飲み込まれる者が飲み込むことになるだろう。","ENG":"When shall the banquet begin?","TWN":"今天的盛宴，是羔羊的血和肉。\\n吞食者將被吞噬，被吞噬者將去吞食。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"연회는 아직인가.","JPN":"宴会はまだか。","ENG":"The long thirst and hunger are finally coming to an end.","TWN":"宴會還沒開始嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"성찬의 주인이 도착했다. 어머니께서 도래하였다.","JPN":"聖餐の主が到着した。お母さんのお出ましだ。","ENG":"The host of the feast has arrived. Mother has arrived.","TWN":"盛宴的主人到了，母親到了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"……이브!","JPN":"……イヴ！","ENG":"...Eve!","TWN":"……伊芙！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L17_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"야, 너 괜찮아? 왜 그렇게 식은 땀을 많이 흘려?","JPN":"ちょっと、あなた大丈夫？　すごい冷や汗だよ？","ENG":"Hey, are you okay? Why are you sweating so much?","TWN":"喂，你沒事吧？你怎麼出那麼多冷汗？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"으음……. 앤?","JPN":"ううん……アン？","ENG":"Mm... Ann?","TWN":"嗯嗯……安妮？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"또 그 이상한 꿈을 꾼 거야?","JPN":"またあの変な夢をみたの？","ENG":"Did you have that weird dream again?","TWN":"又做了那個奇怪的夢嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"<color=#ffd34c>정신감응</color>이라고 했던가? 너도 참 성가시겠다, 그거.","JPN":"<color=#ffd34c>テレパシー</color>だっけ？　あなたも大変だね。","ENG":"<color=#ffd34c>Telepathy</color>, was it? Seems like a real hassle.","TWN":"<color=#ffd34c>精神感應</color>是吧？那個能力也太煩人了吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"매일매일 그런 꿈을 꾸는데 대체 잠은 어떻게 자냐?","JPN":"毎日そんな夢を見るなんて、ちゃんと眠れてるの？","ENG":"How can you sleep when you have dreams like that every day?","TWN":"每天都做那樣的夢，到底怎麼睡覺啊？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"너무 걱정하지 마. 수녀님도 괜찮을 거라고 했잖아.","JPN":"そんなに心配しないで。シスターも大丈夫って言ってたし。","ENG":"Don't worry. Even Sister Theodora said that it was going to be all right.","TWN":"不過也別太擔心，修女也說過會沒事的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"응, 고마워 앤.","JPN":"うん、ありがとう。アン。","ENG":"Yeah. Thanks, Ann.","TWN":"嗯，謝謝你，安妮。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"서두르자. 또 테스트를 땡땡이 쳤다간, 우리 둘 다 닭장 청소 당번이라고!","JPN":"急ごう。またテストをサボったら、二人ともニワトリ小屋の掃除当番になっちゃう！","ENG":"Let's hurry. If we miss another test, we'll have to clean out the chicken pen!","TWN":"快點吧，如果再不去參加測驗，我們二個就要打掃雞舍了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이제 닭똥이라면 지긋지긋해! 물론 닭고기 스튜는 좋아하지만.","JPN":"もうニワトリの糞は勘弁！　チキンのシチューは好きだけどね。","ENG":"I'm so sick of chicken poop! But I still do like chicken stew.","TWN":"我現在看到雞屎就覺得煩！不過我還是很喜歡燉雞的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"히! 히! 히! 힛! 드디어 만났구나! 가면 카운터! 나는 괴인 999호 간질간지럼!","JPN":"ヒ・ヒ・ヒ・ヒッ！　やっと出会ったな！　仮面カウンター！　オレは怪人999号、クスグリマン！","ENG":"He! He! He! He! We finally met! Masked Counter! I am Monster No. 999, Tickle-tickle!","TWN":"嘿！嘿！嘿！嘿！終於見面了！蒙面制裁者！我是999號怪人，癢癢！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"간질간지럼? 그런 괴인은 없잖아?","JPN":"クスグリマン？　そんな怪人聞いたことないけど？","ENG":"Tickle-tickle? There's no monster named that!","TWN":"癢癢嗎？沒有那樣的怪人吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"눈치 없긴! 대충 있다고 쳐!","JPN":"ちょっと、少しは空気を呼んでよ！","ENG":"C'mon! Just roll with it!","TWN":"真是不識趣！你就當是有吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"아무튼! 이 몸은 웃지 않는 못된 아이들을 혼쭐내는 정의의 괴인이다!","JPN":"とにかく！　オレ様は笑わない悪い子どもたちにぎゃふんと言わせる正義の怪人だ！","ENG":"Anyway! I am the monster of justice who comes to punish naughty children who don't laugh!","TWN":"總之！我是教訓不愛笑的壞孩子的正義魔人！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"내 공격을 받아낼 수 있을까!","JPN":"オレの攻撃を受け止められるかな？","ENG":"Will you be able to withstand my attack?!","TWN":"來試試抵擋我的攻擊吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"간질~ 간질~!","JPN":"こちょこちょ～！","ENG":"Tickle, tickle!","TWN":"我搔～我搔～！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L49_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아핫!","JPN":"あはっ！","ENG":"Ah hah!","TWN":"哈！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아하하하! 알았어, 앤! 웃을 게! 웃을 테니까!","JPN":"あははは！　わかったよ、アン！　笑う！　笑うから！","ENG":"Ah hah hah hah! Okay, Ann! I'll laugh! I promise!","TWN":"哈哈哈！好了啦，安妮！我笑啦！我已經笑啦！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"히! 히! 히! 힛! 그 정도 웃음으로는 어림도 없다! 가면 카운터!","JPN":"ヒ・ヒ・ヒ・ヒッ！　その程度の笑いではダメだ！　仮面カウンター！","ENG":"He! He! He! He! That laugh won't cut it! Masked Counter!","TWN":"嘿！嘿！嘿！嘿！還不夠！蒙面制裁者！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"간질~ 간질~!","JPN":"こちょこちょ～！","ENG":"Tickle, tickle!","TWN":"繼續搔～繼續搔～！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L6_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"아하, 아하하하하하하하하핫! 가, 간지러워, 앤!","JPN":"あは、あははははははははは！　く、くすぐったいよ、アン！","ENG":"Ah hah! Ah hah hah hah hah hah hah hah! I-it tickles, Ann!","TWN":"哈，哈哈哈哈哈哈哈！好，好癢，安妮！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그만, 이제 진짜 그만……!!","JPN":"もうダメ、もう、本当にダメ……！！","ENG":"Stop...! I said, sto–","TWN":"好了啦，別再搔了……！！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"아.","JPN":"あ。","ENG":"Oh.","TWN":"啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"이브! 앤! 너희들 테스트 시작한 지가 언제인데 아직도 여기서……!","JPN":"イヴ！　アン！　あんたたち、とっくにテストは始まってるのに、まだこんなところで……！","ENG":"Eve! Ann! Why are you still here when the test has already begun–","TWN":"伊芙！安妮！測驗都開始多久了，你們怎麼還在這裡……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"너희들! 그새를 못 참고 또 사고를 친 거니!","JPN":"ちょっと、またあんたたちなの！？","ENG":"You two! Causing trouble again?!","TWN":"你們二個！怎麼才一會兒就又闖禍了！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"테오도라 수녀님께 다 이를 거야!","JPN":"シスター・テオドラに言いつけてやるんだから！","ENG":"I'm going to tell on Sister Theodora!","TWN":"我要去告訴狄奧朵拉修女！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"으악! 안경 괴인이다! 빨리 도망치자! 이브!","JPN":"うわっ！　メガネ怪人だ！　早く逃げよう！　イヴ！","ENG":"Agh! It's the eyeglasses monster! Run, Eve!","TWN":"呃啊！是眼鏡怪人！快逃！伊芙！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"둘 다 거기 안 서!?","JPN":"こらっ！　二人とも、待ちなさい！！","ENG":"You two stop right there!","TWN":"你們二個都給我站住！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"이 녀석들! 잡히면 하루 종일 쫄쫄 굶을 줄 알아!!","JPN":"こいつら！　捕まえたら一日ご飯抜きだからね！！","ENG":"You brats...! There will be no meals for the entire day when I catch you!!","TWN":"你們這二個傢伙！要是被我抓住了，就罰你們餓一天的肚子！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"말은 저렇게 하지만, 벤자민 언니가 우리를 굶긴 적은 없다.","JPN":"ああやって言ってるけど、ベンジャミンお姉さんはいつもご飯をくれる。","ENG":"Although she says that, Benjamin always gave us something to eat.","TWN":"話雖這麼說，但班潔明姊姊從沒讓我們挨過餓。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"잔소리가 심한 편이이지만, 이곳 동생들을 진짜 가족처럼 아끼기 때문이다.","JPN":"口うるさい人だけど、ここの子どもたちを本当の家族みたいに思ってくれてるから。","ENG":"Her nagging might be a lot, but I think it's because she cares about us like a real family.","TWN":"雖然比較嘮叨，但是對這裡的弟弟妹妹們就像家人一樣愛護。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>로젠탈 보육원</color>의 일상은 오전 7시에 시작된다.","JPN":"<color=#ffd34c>ローゼンタール保育園</color>の日常は、朝7時から始まる。","ENG":"<color=#ffd34c>Rosenthal Orphanage</color>'s daily routines start at 7 in the morning.","TWN":"<color=#ffd34c>羅森泰育幼院</color>的日常生活是從早上7點開始的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_CHILD"},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"간단히 아침 식사를 마치면, 우리는 적성 교육이라는 걸 받는다.","JPN":"簡単な朝食を済ませると、私たちは適性教育を受ける。","ENG":"After some breakfast, we get something called an aptitude education.","TWN":"簡單地吃完早餐後，我們就會接受適性教育。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"오늘은 그 테스트가 있는 날.","JPN":"今日はそのテストがある日。","ENG":"And today's the day of the aptitude test.","TWN":"今天是有相關測驗的日子。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PRIST_PRYDWEN_NPC_NULL","text":{"KOREA":"지금부터 테스트를 시작하겠다.","JPN":"では、今からテストを始める。","ENG":"The test will start now.","TWN":"現在開始測驗。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIST_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRIST_PRYDWEN_NPC_NULL","text":{"KOREA":"준비된 원생부터 한 사람씩 나와서 테스트에 임하도록.","JPN":"準備が終わった院生から一人ずつ前に出て、テストを受けるように。","ENG":"Those ready to take to the test, please step up one at a time.","TWN":"從準備好的學生開始，一個一個出來參加測驗。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIST_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"narration","speaker":null,"text":{"KOREA":"원장 테오도라 수녀님은 이곳이 성황청의 지원으로 운영되고 있다고 했다.","JPN":"院長のシスター・テオドラは、ここが聖皇庁の支援で運営されていると言っていた。","ENG":"It is said that Dean Theodora operates this place with the support of the Holy Curia.","TWN":"院長狄奧朵拉修女說，這裡是在聖皇廳的支持下運營的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIST_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 로젠탈은 이런저런 사정이 있는 고아들 중, 카운터만 선별한다.","JPN":"だからローゼンタールは、様々な事情を抱える孤児の中でも、カウンターのみを選別している。","ENG":"That's why Rosenthal only accepts orphans who are Counters.","TWN":"因此，會從有各種故事的孤兒中篩選出制裁者。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIST_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"아이들의 카운터 능력을 훈련시켜 사회에 환원하는 것이 로젠탈의 목표.","JPN":"子どもたちのカウンター能力を育て、社会に還元することがローゼンタールの目標なのだ。","ENG":"Rosenthal's goal is to train young Counters and return them to society.","TWN":"羅森泰的目標是訓練孩子們的制裁者能力，並回報社會。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIST_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"실제로 성황청에 스카우트를 받은 아이들도 존재한다고 들었다.","JPN":"実際に聖皇庁からスカウトされた子どもたちも存在すると聞いた。","ENG":"In fact, there are children who were directly scouted by the Holy Curia too.","TWN":"聽說實際上確實有些孩子被聖皇廳選中。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRIST_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EXAMINER_PRYDWEN_NPC_M","text":{"KOREA":"자자, 여러분. 잡담하지 말고 빨리빨리 움직이세요.","JPN":"さて、みなさん。お話ししてないで、早く動いてくださいね。","ENG":"Now, now, everyone. Stop chitchatting and please keep moving.","TWN":"來來來，各位。別閒聊了，快點動起來。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXAMINER_PRYDWEN_NPC_M","text":{"KOREA":"신체 검사 결과표는 이쪽에 제출하고, 다 푼 시험지는 이쪽입니다.","JPN":"身体検査の結果はこっちに提出して、テストの回答用紙はこっちですよ。","ENG":"Submit your physical examination report here, and your test sheet here.","TWN":"體檢結果表交到這邊，做完的考卷放在這邊。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"테스트는 외부의 믿을만한 연구기관에서 진행한다고 들었다.","JPN":"テストは外部の信用できる研究機関で行われると聞いた。","ENG":"I heard the test was conducted by a trustworthy external research institute.","TWN":"聽說測驗是由外部可靠的研究機構進行的。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"채혈을 포함한 신체검사. CRF의 활용 및 집중력 평가 테스트.","JPN":"採血を含む身体検査。CRFの活用および集中力評価テスト。","ENG":"The physical examination includes drawing blood, and the test checks for CRF usage and focus.","TWN":"包括血液採檢在內的體檢，CRF的使用及集中力評價測驗。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"아이들은 퇴소한 뒤 좋은 곳으로 가기 위해 진심으로 테스트에 임한다.","JPN":"子どもたちは保育園を出た後、いいところに行くために本気でテストを受ける。","ENG":"The children here do their best on the test so that they can go to a good place after leaving the orphanage.","TWN":"孩子們為了離開後去個好點的地方，會全力以赴地參加測驗。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"물론, 우리처럼 그렇지 않은 아이들도 있지만.","JPN":"もちろん、私たちのように、そうじゃない子どもたちもいるけど。","ENG":"Of course, there are some children, like us, who don't.","TWN":"當然，也有像我們這樣，不那麼聽話的孩子。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_M","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이브, 그래서 이번에는 몇 층까지 쌓았어?","JPN":"イヴ、それで今日は何個積めたの？","ENG":"Eve? So how many did you stack this time?","TWN":"伊芙，所以這次你堆到幾層了？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"열다섯 개…….","JPN":"15個……","ENG":"Fifteen...","TWN":"十五個……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"쳇, 나도 비슷해.","JPN":"チッ、私もそれくらい。","ENG":"Tch, same here.","TWN":"嘖，我也差不多。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"에잇! 나무 블록을 높이 쌓는 게 카운터 능력이랑 대체 무슨 상관이야?","JPN":"ええいっ！　木のブロックを高く積むのとカウンター能力と、なんの関係があるのよ？","ENG":"Ugh! What does stacking blocks have to do with Counter abilities, anyway?","TWN":"呵！把積木堆得高高的跟制裁者能力到底有什麼關係？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"무슨 상관이냐니…… 집중력과 정교함을 평가한다고 했잖아.","JPN":"何の関係って……集中力と精巧さの評価だって言ってたでしょう？","ENG":"Of course it matters... They said they were also evaluating our concentration and dexterity.","TWN":"什麼叫有什麼關係……不是說要評價集中力和精巧度嗎？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"헤엥? 너 바보냐? 그런 걸 믿어?","JPN":"へえっ？　あなた、バカなの？　それ、本気で信じてるの？","ENG":"Hmm? Are you stupid? You really believe that?","TWN":"哈？你是傻瓜嗎？你相信那種鬼話？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"어른들은 등수 놀이 같은 걸 좋아하는 것뿐이야. 이런 건 평가를 위한 평가일 뿐이라고.","JPN":"大人はなんにでも順位をつけたがるのさ。こんなのは評価のための評価ってこと。","ENG":"Those adults just like to rank things. This is just an evaluation for the purpose of evaluating.","TWN":"大人們只是喜歡玩名次遊戲而已，這只是為評價而存在的評價而已。"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"카운터는 원래 가면 카운터처럼 짱 세고, 짱 멋있기만 하면 그만이거든!","JPN":"カウンターはそもそも仮面カウンターみたいに強くて、カッコよければそれでヨシ！","ENG":"All that Counters need to be is cool and super strong! Like the Masked Counter!","TWN":"制裁者本來就只要像蒙面制裁者一樣厲害，帥氣就行！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이렇게……! 합! 하아아앗!","JPN":"こんなに……！　はっ！　はあああっ！","ENG":"Just like this...! Haah! Hya!","TWN":"就像這樣……！哈！哈啊啊啊！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"EXAMINER_PRYDWEN_NPC_F","text":{"KOREA":"……꺅!","JPN":"……きゃっ！","ENG":"...Kyaaa!","TWN":"……呀！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_F","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"아! 죄송해요! 괜찮으세요?","JPN":"あ！　すみません！　大丈夫ですか？","ENG":"Oops! I'm sorry! Are you okay?","TWN":"啊！對不起！你沒事吧？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"EXAMINER_PRYDWEN_NPC_F","text":{"KOREA":"불결하게 내 몸에 손대지 마!","JPN":"汚い手で私の体に触れないで！","ENG":"Filthy child! Don't touch me!","TWN":"髒死了，別碰我！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_F","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"EXAMINER_PRYDWEN_NPC_F","text":{"KOREA":"부모도 없는 괴물들 주제에……!","JPN":"親もいない化け物のくせに……！","ENG":"You're nothing but monsters abandoned by your parents...!","TWN":"一群沒有父母的怪物………！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXAMINER_PRYDWEN_NPC_F","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"뭐야, 그렇게까지 말할 필요는 없잖아…….","JPN":"何よ、そんな言い方することないでしょ……","ENG":"Yeesh... She didn't have to be that rude...","TWN":"什麼啊，沒必要那麼說吧……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"앤…….","JPN":"アン……","ENG":"Ann...","TWN":"安妮……"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"쿠, 쿠와아아앙!?","JPN":"ぐ、ぐわあああ！？","ENG":"K-kwaaar?!","TWN":"吼，吼吼吼吼？！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"이브?","JPN":"イヴ？","ENG":"Eve?","TWN":"伊芙？"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"괴인 간질간지럼인 거예요! 웃지 않는 아이는 호, 혼내 줄 거예요!","JPN":"怪人クスグリマンです！　笑わない子どもはぎゃ、ぎゃふんと言わせちゃいますからね！","ENG":"I'm the Tickle-tickle monster! I-I'm here to punish children who don't laugh!","TWN":"我是怪人癢癢！我要教，教訓不喜歡笑的孩子！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"쿠와아아아앙!","JPN":"ぐわあああ！","ENG":"Kwarrr!","TWN":"吼吼吼吼吼！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"……풉!","JPN":"……プッ。","ENG":"...Pfft!","TWN":"……噗！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"푸하하하하하하핫! 그게 뭐야!","JPN":"あはははははははっ！　何よそれ！","ENG":"Ahahahaha! What was that?","TWN":"噗哈哈哈哈哈！那是什麼！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"좋아! 이제야 나타났구나! 괴인 간질간지럼!","JPN":"よーし！　ついに現われたな！　怪人クスグリマン！","ENG":"Okay! You've finally shown your face! Tickle-tickle monster!","TWN":"好啊！你現在才出現！怪人癢癢！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"그렇다면, 이 가면 카운터가 네놈을 직접 상대해주마!","JPN":"そうときたら、この仮面カウンターが直接、貴様の相手になってやる！","ENG":"Then, the Masked Counter will take you on!","TWN":"那麼，就讓我蒙面制裁者來對付你吧！"},"stage":{"bg":"LABORATORY_03","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"로젠탈을 떠난 뒤의 일 같은 건 생각해본 적 없다.","JPN":"ローゼンタールから出た後のことなんて考えたこともない。","ENG":"I've never thought about what would happen after I left Rosenthal.","TWN":"我從未想過離開羅森泰之後的事情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"다른 아이들처럼 좋은 곳으로 가고 싶다고도 생각해본 적 없다.","JPN":"他の子どもたちのように、いいところに行きたいとも思っていない。","ENG":"Unlike the other children, I never wanted to go somewhere else.","TWN":"我從未想過要像其他孩子一樣去好個地方。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"왜냐하면…….","JPN":"なぜなら……","ENG":"Because...","TWN":"因為……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"왜냐하면, 이곳에서 만난 친구들과 함께 지내는 것만으로도 행복했기 때문에.","JPN":"なぜなら、ここで出会った友だちと一緒にいるだけで、十分幸せだったから。","ENG":"Because I was happy just being here with the friends I've made.","TWN":"因為能在這裡和大家一起生活就已經很幸福了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"같이 있는 것만으로도 웃을 수 있었기 때문이다.","JPN":"一緒にいるだけで笑顔になれたから。","ENG":"Just being able to be together and laugh was all that I wanted.","TWN":"因為只要在一起就能笑出來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"하지만.","JPN":"でも……","ENG":"But.","TWN":"但是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"자, 여러분. 오늘은 한 가지 기쁜 소식이 있어요.","JPN":"はい、みんな。今日はいいお知らせが一つありますよ。","ENG":"Okay, everyone. Today, I have an exciting announcement.","TWN":"來，各位，今天有一個好消息。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"벤자민 양이 적성을 인정받아 제약 회사의 스카우트 제안를 받았답니다.","JPN":"ベンジャミンさんが適性を認められ、製薬会社にスカウトされました。","ENG":"Benjamin was recognized for her aptitude evaluation and was offered a job at a pharmaceutical company.","TWN":"班潔明的適性得到認可，被製藥公司選上了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"그래서 아쉽지만, 오늘을 마지막으로 벤자민 양은 로젠탈을 퇴소하게 되었어요.","JPN":"ということで残念ですが、ベンジャミンさんとは今日でお別れになります。","ENG":"It's sad to see her go, but today will be Benjamin's last day at the orphanage.","TWN":"雖然有點捨不得，但今天是班潔明在這裡的最後一天，明天她要離開羅森泰了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"자, 다들 벤자민 양에게 박수!","JPN":"はい、みんな、ベンジャミンさんに拍手！","ENG":"Now, give Benjamin a big round of applause!","TWN":"大家給班潔明鼓掌！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHILDREN_PRYDWEN_NPC_NULL","text":{"KOREA":"축하해요, 벤자민 언니!","JPN":"おめでとう、ベンジャミンお姉ちゃん！","ENG":"Congrats, Benjamin!","TWN":"恭喜你，班潔明姊姊！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHILDREN_PRYDWEN_NPC_NULL","text":{"KOREA":"좋은데 갔다고, 우릴 잊는 건 아니지?","JPN":"いいところ行っても、私たちのこと忘れないでね？","ENG":"You're not going to forget about us just because you got a cushy job now, are you?","TWN":"你不會因為去了好地方就忘了我們吧？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"다들 고마워. 가끔 보육원에 선물 보낼게.","JPN":"みんな、ありがとう。たまに保育園にプレゼントを送るね。","ENG":"Thanks, everyone. I'll send you some gifts.","TWN":"謝謝大家，我偶爾會給育幼院發禮物的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"자, 음식 식겠어. 다들 빨리 먹자!","JPN":"料理が冷めちゃう。みんな、早く食べよう！","ENG":"Now then, let's eat before all the food gets cold!","TWN":"來，菜要涼了，大家快點吃吧！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"얘들아 잠깐만! 벤자민 언니, 이브가 할 말 있대!","JPN":"ちょっと待って！　ベンジャミンお姉さん、イヴから話があるんだって！","ENG":"Guys, wait! Before we eat, Eve has something to say to Benjamin!","TWN":"大家等一下！班潔明姊姊，伊芙有話要說！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"내, 내가 언제……!","JPN":"わ、私がいつ……！","ENG":"W-when did I say that...?!","TWN":"我，我什麼時候……！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"바보야! 그럼 이대로 쭈뼛거리면서 작별 인사도 안 할 거야?","JPN":"バカ！　じゃあ、このままさよならも言わないつもり？","ENG":"C'mon, you idiot! Then are you really just going to stand there and not say goodbye to her?","TWN":"傻瓜！那你就準備這樣畏畏縮縮地連再見都不說嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그건 아니지만…….","JPN":"それは違うけど……","ENG":"No, but...","TWN":"那倒不是……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"하하, 이브구나? 할 말이라는 게 뭐야?","JPN":"はは、イヴ。話って何？","ENG":"Haha, Eve? So what did you want to tell me?","TWN":"哈哈，原來是伊芙啊？你想對我說什麼？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……흑.","JPN":"……ううっ。","ENG":"*Sniffle...*","TWN":"……嗚。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"흐윽. 언니 안 가면 안 돼요?","JPN":"ううっ。お姉さん、本当に行かなきゃダメなんですか？","ENG":"Hngh... Do you really have to go?","TWN":"嗚嗚，姊姊可不可以不要走？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"지금처럼 우리 계속 여기서 살아요. 네?","JPN":"今までみたいに、ずっとここで一緒に暮らしましょうよ。ねぇ？","ENG":"Can't we just live here like we always have? Hmm?","TWN":"像現在這樣，我們繼續住在這裡吧，好不好？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"언니가 없으면 저 너무 슬플 것 같아요. 그러니까…… 끄윽!","JPN":"お姉さんがいないと、私……寂しいんです。だから……ううっ！","ENG":"I think I'm going to be sad without you here. So... *Sniffle.*","TWN":"姊姊不在，我會很傷心的。所以……嗚嗚！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"걱정하지 마. 어차피 영영 못 보게 되는 것도 아닌 걸?","JPN":"大丈夫。永遠の別れってわけじゃないんだから。","ENG":"Don't worry. It's not like we're never going to see each other again.","TWN":"別擔心，反正也不是永遠見不到。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"내가 없어도 다들 금방 괜찮아질 거야.","JPN":"私のことなんて、すぐに忘れられるわ。","ENG":"I'm sure you'll be all right without me.","TWN":"即使我不在，大家也會很快就習慣了的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"이브도 열심히 적성을 키워서 나보다 더 좋은 곳으로 가야지, 안 그래?","JPN":"イヴは頑張って適性を育てて、私よりいいところに行かないと。そうでしょう？","ENG":"And Eve, you should also develop your aptitude to get a better job than me, okay?","TWN":"伊芙也要努力成長，然後去比我更好的地方，不是嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"그건, 그렇지만…….","JPN":"それは、そうですけど……","ENG":"Okay, but still...","TWN":"那個，可是……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"안 되겠네. 우는 아이에게는 선물을 주면 안 되지만.","JPN":"仕方ないわね。泣く子にはプレゼントをあげちゃダメなんだけど。","ENG":"Oh, well. Although I'm not supposed to give crying children presents...","TWN":"真是的，雖說不能給哭的孩子禮物。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"이번만 특별히 선물! 내가 잘 때 끌어안고 자는 애착 인형이야.","JPN":"今日だけは特別！　私がいつも一緒に寝てるぬいぐるみだよ。","ENG":"I'll make an exception and give you something special! This is my stuffed animal that I sleep with.","TWN":"但這一次給你破例吧！是我睡覺的時候抱著的娃娃。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"토끼 인형…….","JPN":"ウサギのぬいぐるみ……","ENG":"A rabbit doll...","TWN":"兔子娃娃……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"하하, 맞아. 조금 낡았기는 한데, 이브 줄게. 나 대신 소중히 여겨줘야 해?","JPN":"あはは、そう。ちょっとボロいけど、イヴにあげる。私の代わりに大事にしてね？","ENG":"Haha, yup. It's a little tattered, but I'll give it to you, Eve. Instead, you have to take good care of it, okay?","TWN":"哈哈，沒錯。雖然有點舊了，但還是給你吧。你要替我好好珍惜喔？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BENJAMIN_PRYDWEN_NPC_NULL","text":{"KOREA":"자, 그럼 뚝!","JPN":"はい、もう泣かない！","ENG":"All right. Now no more crying!","TWN":"好，別哭啦！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENJAMIN_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……뚝!","JPN":"……ひっく！","ENG":"...No more crying!","TWN":"……不哭！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L34_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"고마워요, 벤자민 언니.","JPN":"ありがとう、ベンジャミンお姉さん。","ENG":"Thanks, Benjamin.","TWN":"謝謝你，班潔明姊姊。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"저…… 꼭 소중하게 간직할 게요.","JPN":"私……絶対大事にします。","ENG":"I'll... take real good care of it.","TWN":"我……一定會好好珍惜這個娃娃的。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"자, 여러분! 성찬을 들기 전에 벤자민 양을 위해 어머니께 감사 기도를 올립시다!","JPN":"はい、みんな！　聖餐を食べる前に、ベンジャミンさんを想ってお母さんに感謝の祈りを捧げましょう！","ENG":"Okay, everyone! Before we start the feast, let's say a prayer to thank Mother for Benjamin!","TWN":"好了，各位！在享受盛宴之前，讓我們為班潔明向母親祈禱致謝吧！"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"이 음식들은 모두 어머니의 피와 살로 만든 성찬이에요.","JPN":"この食べ物は、すべてお母さんの血と肉で作られた聖餐です。","ENG":"All this food is communion made from our Mother's flesh and blood.","TWN":"這些食物都是用母親的血肉做成的盛宴。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"모두 벤자민 양의 앞날을 위해 축복하는 마음으로 성찬을 들도록 해요.","JPN":"みんな、ベンジャミンさんの未来を祝福する気持ちで聖餐を召し上がってくださいね。","ENG":"So everyone should all eat while praying for Benjamin's bright future ahead of her.","TWN":"大家為了班潔明的未來，懷著祝福的心情享用盛宴吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 그때 우리는 아직 알지 못했다.","JPN":"だけど、その時の私たちはまだ知らなかった。","ENG":"But we didn't know back then.","TWN":"但是那時候我們還不知道。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"우리에게, 그리고 이 보육원에 어떤 일이 생길지를.","JPN":"私たちに、そしてこの保育園にどんなことが起こるのかを。","ENG":"About what will happen to us, or the orphanage.","TWN":"我們，還有這個育幼院會發生什麼事情。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"성찬을 준비하라. 새로운 날이 당도하리니.","JPN":"聖餐を準備しろ。新しい日が到来する。","ENG":"Prepare the feast. A new dawn is coming.","TWN":"預備盛宴吧。新天已來到。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"불완전한 지식, 불완전한 존재들이 성찬을 통해 하나가 되어, 완전해질 것이다.","JPN":"不完全な知識、不完全な存在たちが聖餐により一つになり、完全体となる。","ENG":"The feast will complete the imperfect knowledge and perfect the imperfect beings.","TWN":"不完整的知識，不完整的存在將透過盛宴合而為一，變得完整。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"모두 지식의 성찬을 준비하라.\\n모두 연회를 시작하라.","JPN":"みんな、知識の聖餐を準備しろ。\\nみんな、宴会を始めろ。","ENG":"Prepare the feast of knowledge.\\nStart the banquet.","TWN":"大家準備知識的盛宴吧，\\n大家開始宴會吧。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"오랜 갈구와 허기의 끝이 마침내 도래했다.","JPN":"長い渇きと飢えの果てが、ついに訪れたのだ。","ENG":"Today, the blood and flesh of the young lamb will be on the table,\\nand the swallower shall become the swallowed.","TWN":"長久的渴望與饑餓終於到達了盡頭。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"오늘의 성찬은 어린 양의 피와 살일지니.\\n삼키는 자가 삼켜지고, 삼켜지는 자가 삼키리라.","JPN":"今日は子羊の血と肉が聖餐となり、\\n飲み込む者が飲み込まれ、飲み込まれる者が飲み込むことになるだろう。","ENG":"When shall the banquet begin?","TWN":"今天的盛宴，是羔羊的血和肉。\\n吞食者將被吞噬，被吞噬者將去吞食。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"연회는 아직인가.","JPN":"宴会はまだか。","ENG":"The long thirst and hunger are finally coming to an end.","TWN":"宴會還沒開始嗎？"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"성찬의 주인이 도착했다. 어머니께서 도래하였다.","JPN":"聖餐の主が到着した。お母さんのお出ましだ。","ENG":"The host of the feast has arrived. Mother has arrived.","TWN":"盛宴的主人到了，母親到了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OCTOPUS3_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_QM","text":{"KOREA":"……이브!","JPN":"……イヴ！","ENG":"...Eve!","TWN":"……伊芙！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L13_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"으음…… 앤?","JPN":"ううん……アン？","ENG":"Mm... Ann?","TWN":"呃………安妮？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"얌마, 빨리 일어나 이브! 또 늦잠 잘 셈이야?","JPN":"ちょっと、早く起きてよ、イヴ！　また寝坊する気？","ENG":"Wake up, sleepyhead! How much longer are you gonna stay in bed?","TWN":"喂，快起來啊，伊芙！又想睡懶覺嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"으음? 뭐야, 그 누더기 같은 인형은?","JPN":"うーん？　何、そのボロボロの人形。","ENG":"Mm... huh? What's that rag doll you got there?","TWN":"嗯？這個破爛的娃娃是誰的？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"……누더기?","JPN":"……ボロボロ？","ENG":"...Rag?","TWN":"……破爛？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"누더기라니……!","JPN":"ボロボロって……！","ENG":"Don't call it that...!","TWN":"怎麼能說是破爛呢……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"어떻게 그렇게 심한 말을 할 수 있어!?","JPN":"どうしてそんなひどいこと言うの！？","ENG":"How can you say something so mean?!","TWN":"怎麼能說那麼過分的話？！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANNE_PRYDWEN_NPC_NULL","text":{"KOREA":"왜 그렇게 화를 내고 그래!? 기분 나쁜 걸 기분 나쁘다고 한 건데…….","JPN":"なんで怒るんだよ！？　本当のこと言っただけじゃん……","ENG":"What are you getting angry at me for?! I'm just saying what was on my mind...","TWN":"幹嘛生那麼大的氣啊？！心情不好就好好說出來嘛……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANNE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"무슨 소리 하는 거야……?","JPN":"何を言ってるの……？","ENG":"What are you talking about...?","TWN":"你在說什麼呢……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"너도 같이 봤잖아?","JPN":"あなたも一緒に見たでしょう？","ENG":"You saw it with me.","TWN":"你不是也看到了嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"EVE_PRYDWEN_NPC_NULL","text":{"KOREA":"이 인형은, 이 인형은! 어제 성찬식에서……!","JPN":"このぬいぐるみは……このぬいぐるみは！　昨日の聖餐式で……！","ENG":"This doll... This doll was! At yesterday's feast...!","TWN":"這個娃娃，這個娃娃！是在昨天的盛宴儀式上……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVE_PRYDWEN_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"narration","speaker":null,"text":{"KOREA":"성찬식에서.","JPN":"聖餐式で。","ENG":"At the feast.","TWN":"昨天的盛宴儀式上……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"인형을 준 게…… 누구였지?","JPN":"ぬいぐるみをくれたのは……誰……？","ENG":"Who gave me... this doll?","TWN":"是誰……給我的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};